  ('generalpolice-94737317-moex-00018', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '兩個相距為R的點電荷q、q，其間的靜電力為F。若兩點電荷間距變為2R，q 增為2q 且q 增為', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00019', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '2 1 1 2 3q，則兩點電荷間的靜電力變為多少？ 2', '["F", "6F", "F/4", "3F/2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
