  ('generalpolice-94737317-moex-00021', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '在真空中有兩組平行電板，如圖所示，左側兩片電板的電位差為 V，提供電子的加速作用；右側兩 1 片電板的電位差為 V，提供電子的偏向作用。電子在左側兩電板間由靜止開始向正右方運動，射入 2 右側兩平行電板中，入射方向與右側兩帶電板平行。若忽略重力，則在滿足電子能射出平行板的條件 下，下列那種實驗改變，一定能使電子的偏轉角度θ變大？', '["V 變大、V 變大", "V 變小、V 變大", "V 變大、V 變小", "V 變小、V 變小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
